#include <iostream>
#include<climits>
#include<vector>
using namespace std;
int fun(vector<int>areas, vector<int>&prices,vector<int>&dp,int ar, int pr, int i,int k)
{
    if(k == 0)
    {
        float xy = ((float)pr/ar);
        int st = xy*1e6;
        return st;
    }
    if(i >= areas.size())
     return INT_MIN;
     if(k < 0)
     return INT_MIN;
     if(dp[i] != -1)
     return dp[i];
     int a = INT_MIN;
     for(int start = i; start < areas.size(); start++)
     {
         a = max(a, fun(areas,prices,dp,ar+areas[start],pr+prices[start],start+1,k-1));
     }
     return dp[i] = a;
}
int calculate(vector<int>&area, vector<int>&price,int k,int N)
{
    vector<int>dp(N+1, -1);
    return fun(area,price,dp,0,0,0,k);
}

int main()
{
    int k,N;
    cout<<"enter the value of size of vector\n";
    cin>>N;
    cout<<"enter the value of k \n";
    cin>>k;
    vector<int>area(N,0);
    vector<int>price(N,0);
    int a=0,b=0;
    cout<<"enter the value of area vector\n";
    for(int i=0;i<N;i++)
    {
        cin>>a;
        area[i] = a;
    }
    cout<<"enter the value of price of vector\n";
    for(int i=0;i<N;i++)
    {
        cin>>b;
        price[i] = b;
    }
    int xy = calculate(area,price,k,N);
    cout<<xy<<" ";

    return 0;
}
